/**
 * Header JavaScript
 * This script handles the functionality for the site header, including the profile dropdown
 */

document.addEventListener('DOMContentLoaded', function () {
  // Initialize the header
  initHeader();
});

/**
* Initialize all header functionality
*/
function initHeader() {
  // Setup profile dropdown toggle
  setupProfileDropdown();

  // Add navigation event listeners
  setupNavigation();

  // Check if user is logged in and update UI accordingly
  checkLoginStatus();
}

/**
* Setup the profile dropdown functionality
*/
function setupProfileDropdown() {
  const userProfile = document.querySelector('.user-profile');

  // If the user profile element exists in the header
  if (userProfile) {
    // Create dropdown menu if it doesn't exist yet
    if (!document.querySelector('.profile-dropdown')) {
      createProfileDropdown(userProfile);
    }

    // Toggle dropdown visibility on click
    userProfile.addEventListener('click', function (e) {
      const dropdown = document.querySelector('.profile-dropdown');
      if (dropdown) {
        dropdown.classList.toggle('active');

        // Stop propagation to prevent document click from immediately closing it
        e.stopPropagation();
      }
    });

    // Close dropdown when clicking elsewhere on the page
    document.addEventListener('click', function (e) {
      const dropdown = document.querySelector('.profile-dropdown');
      if (dropdown && dropdown.classList.contains('active')) {
        dropdown.classList.remove('active');
      }
    });
  }
}

/**
* Create the profile dropdown menu
* @param {HTMLElement} parentElement - The parent element to append the dropdown to
*/
function createProfileDropdown(parentElement) {
  const dropdown = document.createElement('div');
  dropdown.className = 'profile-dropdown';

  // Create dropdown items
  const menuItems = [{
    text: 'Account Settings',
    url: 'account.html'
  }, {
    text: 'Edit Profile',
    url: 'edit-profile.html'
  }, {
    text: 'Order History',
    url: 'orders.html'
  }, {
    text: 'Addresses',
    url: 'manage-addresses.html'
  }, {
    text: 'Payment Methods',
    url: 'payment-methods.html'
  }, {
    text: 'Logout',
    url: '#',
    id: 'logout-btn'
  }];

  // Create and append each menu item
  menuItems.forEach(item => {
    const menuItem = document.createElement('a');
    menuItem.href = item.url;
    menuItem.textContent = item.text;
    if (item.id) {
      menuItem.id = item.id;
    }
    dropdown.appendChild(menuItem);
  });

  // Add logout functionality
  dropdown.querySelector('#logout-btn').addEventListener('click', function (e) {
    e.preventDefault();
    logoutUser();
  });

  // Append dropdown to parent
  parentElement.appendChild(dropdown);
}

/**
* Setup navigation event listeners
*/
function setupNavigation() {
  // Add event listeners for any navigation elements
  const navLinks = document.querySelectorAll('nav a');
  navLinks.forEach(link => {
    link.addEventListener('click', function (e) {
      // Example: track navigation clicks
      trackNavigation(this.textContent, this.getAttribute('href'));
    });
  });
}

/**
* Check user login status and update UI accordingly
*/
function checkLoginStatus() {
  // Get user data from storage
  const userData = localStorage.getItem('userData');
  if (userData) {
    // User is logged in
    const user = JSON.parse(userData);
    updateHeaderUI(user);
  } else {
    // User is not logged in
    showLoginButton();
  }
}

/**
* Update header UI with user data
* @param {Object} user - The user data object
*/
function updateHeaderUI(user) {
  // Update user name
  const userNameElement = document.querySelector('.user-name');
  if (userNameElement) {
    userNameElement.textContent = user.name;
  }

  // Update profile image
  const profileImageElement = document.querySelector('.profile-image img');
  if (profileImageElement && user.profileImage) {
    profileImageElement.src = user.profileImage;
    profileImageElement.alt = `${user.name}'s Profile Picture`;
  }

  // If there are notifications, show an indicator
  if (user.hasNotifications) {
    const notificationIndicator = document.createElement('div');
    notificationIndicator.className = 'notification-indicator';
    const userProfile = document.querySelector('.user-profile');
    if (userProfile) {
      userProfile.appendChild(notificationIndicator);
    }
  }
}

/**
* Show login button instead of profile when user is not logged in
*/
function showLoginButton() {
  const userProfile = document.querySelector('.user-profile');
  if (userProfile) {
    // Clear existing content
    userProfile.innerHTML = '';

    // Create login button
    const loginButton = document.createElement('a');
    loginButton.href = 'login.html';
    loginButton.className = 'login-button';
    loginButton.textContent = 'Sign In';
    userProfile.appendChild(loginButton);
  }
}

/**
* Handle user logout
*/
function logoutUser() {
  // Clear user data
  localStorage.removeItem('userData');

  // Redirect to login page
  window.location.href = 'login.html';
}

